import Expenses from './Components/Expenses/Expenses.js';
function App() {
  let item_list = {
    item1:{
      date: new Date(2021, 5, 23),
      title: "Sleepwell bed",
      amount: 12000
    },
    item2:{
      date: new Date(2021, 5, 20),
      title: "Real Juice",
      amount: 349
    },
    item3:{
      date: new Date(2021, 5, 27),
      title: "Antidandruff shampoo",
      amount: 450
    }
  }
  return (
    <div className="App">
      <h2>Let's get started!</h2>
      <Expenses item_list = {item_list}/>
    </div>
  );
}

export default App;
